# Auto-generated frontend assets for Vercel deployment

INDEX_HTML = '<!DOCTYPE html>\n<html lang="en">\n  <head>\n    <meta charset="UTF-8" />\n    <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n    <title>DichVariables Analysis</title>\n    <link rel="stylesheet" href="/styles.css" />\n  </head>\n  <body>\n    <main>\n      <h1>DichVariables Analysis</h1>\n      <p class="subtitle">\n        Upload a dichotomous dataframe and run segmentation, dendrogram, or\n        graph analysis. Single mode uses VAR_* columns; multiple mode uses\n        {prefix}_{item}_{variable} columns (e.g. IM6_20_11).\n      </p>\n\n      <div class="mode-toggle">\n        <button type="button" id="mode-single" class="mode-btn active">Single mode</button>\n        <button type="button" id="mode-multiple" class="mode-btn">Multiple mode</button>\n      </div>\n\n      <form id="analyze-form">\n        <div class="card">\n          <h2>Request payload (JSON)</h2>\n          <label for="payload">variables, groups, mode, outputs</label>\n          <textarea id="payload" spellcheck="false"></textarea>\n        </div>\n\n        <div class="card">\n          <h2>Dataframe (Arrow IPC)</h2>\n          <label for="dataframe" id="column-hint">\n            Columns: VAR_1, VAR_2, … plus weight column (e.g. wrakin1)\n          </label>\n          <input\n            id="dataframe"\n            type="file"\n            accept=".arrow,.ipc,application/octet-stream"\n          />\n        </div>\n\n        <div id="error" class="error hidden"></div>\n\n        <div class="actions">\n          <button type="submit" id="submit-btn">Run analysis</button>\n        </div>\n      </form>\n\n      <div id="results" class="results-grid hidden"></div>\n    </main>\n    <script src="/app.js"></script>\n  </body>\n</html>\n'

APP_JS = 'const EXAMPLE_PAYLOAD_SINGLE = {\n  variables: {\n    "1": {\n      short_description: "Var 1",\n      long_description: "First variable",\n      group_id: 10,\n    },\n    "2": {\n      short_description: "Var 2",\n      long_description: "Second variable",\n      group_id: 10,\n    },\n  },\n  groups: {\n    "10": {\n      short_description: "Group A",\n      long_description: "Variable group A",\n    },\n  },\n  mode: "single",\n  weight_column: "wrakin1",\n  outputs: {\n    segmentation: { num_segments: 3 },\n    dendrogram: {\n      distance: "simpson",\n      grouping: "average",\n      num_groups: 3,\n      image_width: 1400,\n      image_height: 900,\n      image_dpi: 200,\n    },\n    graph: { distance: "jaccard" },\n  },\n};\n\nconst EXAMPLE_PAYLOAD_MULTIPLE = {\n  variables: {\n    "1": {\n      short_description: "Trait 1",\n      long_description: "First trait",\n    },\n    "2": {\n      short_description: "Trait 2",\n      long_description: "Second trait",\n    },\n  },\n  mode: "multiple",\n  column_prefix: "IM6",\n  items: {\n    "101": {\n      short_description: "Brand A",\n      long_description: "Brand A full name",\n    },\n    "102": {\n      short_description: "Brand B",\n      long_description: "Brand B full name",\n    },\n  },\n  weight_column: "wrakin1",\n  outputs: {\n    segmentation: { num_segments: 3 },\n    dendrogram: {\n      distance: "simpson",\n      grouping: "average",\n      num_groups: 2,\n    },\n    graph: { distance: "jaccard" },\n  },\n};\n\nconst payloadEl = document.getElementById("payload");\nconst formEl = document.getElementById("analyze-form");\nconst fileEl = document.getElementById("dataframe");\nconst errorEl = document.getElementById("error");\nconst resultsEl = document.getElementById("results");\nconst submitBtn = document.getElementById("submit-btn");\nconst modeSingleBtn = document.getElementById("mode-single");\nconst modeMultipleBtn = document.getElementById("mode-multiple");\nconst columnHintEl = document.getElementById("column-hint");\n\nlet activeMode = "single";\n\nfunction setMode(mode) {\n  activeMode = mode;\n  modeSingleBtn.classList.toggle("active", mode === "single");\n  modeMultipleBtn.classList.toggle("active", mode === "multiple");\n  payloadEl.value = JSON.stringify(\n    mode === "single" ? EXAMPLE_PAYLOAD_SINGLE : EXAMPLE_PAYLOAD_MULTIPLE,\n    null,\n    2,\n  );\n  columnHintEl.textContent =\n    mode === "single"\n      ? "Columns: VAR_1, VAR_2, … plus weight column (e.g. wrakin1)"\n      : "Columns: {prefix}_{item}_{var} (e.g. IM6_101_1, IM6_102_2), plus weight column";\n}\n\nmodeSingleBtn.addEventListener("click", () => setMode("single"));\nmodeMultipleBtn.addEventListener("click", () => setMode("multiple"));\n\nsetMode("single");\n\nfunction showError(message) {\n  errorEl.textContent = message;\n  errorEl.classList.remove("hidden");\n}\n\nfunction clearError() {\n  errorEl.textContent = "";\n  errorEl.classList.add("hidden");\n}\n\nfunction renderResults(data) {\n  resultsEl.innerHTML = "";\n  resultsEl.classList.remove("hidden");\n\n  if (data.dendrogram) {\n    const d = data.dendrogram;\n    const card = document.createElement("div");\n    card.className = "card";\n    card.innerHTML = `\n      <h2>Dendrogram</h2>\n      <div class="meta-row">\n        <span>Distance: <strong>${d.distance}</strong></span>\n        <span>Grouping: <strong>${d.grouping}</strong></span>\n        <span>Groups: <strong>${d.num_groups}</strong></span>\n      </div>\n      <img class="dendrogram-img" alt="Dendrogram" src="data:image/png;base64,${d.image_png_base64}" />\n      <div class="actions">\n        <button type="button" id="download-png">Download PNG</button>\n      </div>\n      <h2 style="margin-top:1.25rem">Cluster assignments</h2>\n      <pre class="json-out"></pre>\n    `;\n    card.querySelector("pre").textContent = JSON.stringify(\n      d.cluster_assignments,\n      null,\n      2,\n    );\n    card.querySelector("#download-png").addEventListener("click", () => {\n      const link = document.createElement("a");\n      link.href = `data:image/png;base64,${d.image_png_base64}`;\n      link.download = `dendrogram_${d.distance}_${d.grouping}.png`;\n      link.click();\n    });\n    resultsEl.appendChild(card);\n  }\n\n  if (data.segmentation) {\n    const s = data.segmentation;\n    const card = document.createElement("div");\n    card.className = "card";\n    card.innerHTML = `\n      <h2>Segmentation</h2>\n      <div class="meta-row">\n        <span>Segments: <strong>${s.num_segments}</strong></span>\n      </div>\n      <pre class="json-out"></pre>\n    `;\n    card.querySelector("pre").textContent = JSON.stringify(\n      s.assignments,\n      null,\n      2,\n    );\n    resultsEl.appendChild(card);\n  }\n\n  if (data.graph) {\n    const g = data.graph;\n    const card = document.createElement("div");\n    card.className = "card";\n    const edgesPreview = g.edges.slice(0, 50);\n    let text = JSON.stringify(edgesPreview, null, 2);\n    if (g.edges.length > 50) text += "\\n… (truncated)";\n    card.innerHTML = `\n      <h2>Graph</h2>\n      <div class="meta-row">\n        <span>Distance: <strong>${g.distance}</strong></span>\n        <span>Nodes: <strong>${g.nodes.length}</strong></span>\n        <span>Edges: <strong>${g.edges.length}</strong></span>\n      </div>\n      <pre class="json-out"></pre>\n    `;\n    card.querySelector("pre").textContent = text;\n    resultsEl.appendChild(card);\n  }\n}\n\nformEl.addEventListener("submit", async (e) => {\n  e.preventDefault();\n  clearError();\n  resultsEl.classList.add("hidden");\n\n  const file = fileEl.files?.[0];\n  if (!file) {\n    showError("Please select an Arrow IPC dataframe file.");\n    return;\n  }\n\n  try {\n    JSON.parse(payloadEl.value);\n  } catch {\n    showError("Payload is not valid JSON.");\n    return;\n  }\n\n  const form = new FormData();\n  form.append("payload", payloadEl.value);\n  form.append("dataframe", file);\n\n  submitBtn.disabled = true;\n  submitBtn.textContent = "Analyzing…";\n\n  try {\n    const res = await fetch("/api/v1/analyze", { method: "POST", body: form });\n    const body = await res.json();\n    if (!res.ok) {\n      const detail =\n        typeof body.detail === "string"\n          ? body.detail\n          : JSON.stringify(body.detail, null, 2);\n      throw new Error(detail || `Request failed (${res.status})`);\n    }\n    renderResults(body);\n  } catch (err) {\n    showError(err instanceof Error ? err.message : "Request failed");\n  } finally {\n    submitBtn.disabled = false;\n    submitBtn.textContent = "Run analysis";\n  }\n});\n'

STYLES_CSS = '*,\n*::before,\n*::after {\n  box-sizing: border-box;\n}\n\n:root {\n  --bg: #0f1419;\n  --surface: #1a2332;\n  --border: #2d3a4f;\n  --text: #e8edf4;\n  --muted: #8b9cb3;\n  --accent: #3b82f6;\n  --accent-hover: #2563eb;\n  --error: #ef4444;\n}\n\nhtml,\nbody {\n  margin: 0;\n  padding: 0;\n  min-height: 100vh;\n  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;\n  background: var(--bg);\n  color: var(--text);\n  line-height: 1.5;\n}\n\nmain {\n  max-width: 1100px;\n  margin: 0 auto;\n  padding: 2rem 1.5rem 4rem;\n}\n\nh1 {\n  font-size: 1.75rem;\n  font-weight: 600;\n  margin: 0 0 0.5rem;\n}\n\n.subtitle {\n  color: var(--muted);\n  margin: 0 0 1.25rem;\n}\n\n.mode-toggle {\n  display: flex;\n  gap: 0.5rem;\n  margin-bottom: 1.5rem;\n}\n\n.mode-btn {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  color: var(--muted);\n  padding: 0.5rem 1rem;\n  font-size: 0.875rem;\n}\n\n.mode-btn:hover:not(:disabled) {\n  background: var(--surface);\n  border-color: var(--accent);\n  color: var(--text);\n}\n\n.mode-btn.active {\n  background: var(--accent);\n  border-color: var(--accent);\n  color: white;\n}\n\n.mode-btn.active:hover:not(:disabled) {\n  background: var(--accent-hover);\n  border-color: var(--accent-hover);\n}\n\n.card {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 12px;\n  padding: 1.25rem;\n  margin-bottom: 1.25rem;\n}\n\n.card h2 {\n  font-size: 1rem;\n  font-weight: 600;\n  margin: 0 0 1rem;\n}\n\nlabel {\n  display: block;\n  font-size: 0.875rem;\n  font-weight: 500;\n  margin-bottom: 0.5rem;\n}\n\ntextarea {\n  width: 100%;\n  min-height: 280px;\n  padding: 0.75rem;\n  font-family: ui-monospace, "Cascadia Code", monospace;\n  font-size: 0.8rem;\n  background: var(--bg);\n  color: var(--text);\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  resize: vertical;\n}\n\ninput[type="file"] {\n  width: 100%;\n  padding: 0.5rem;\n  background: var(--bg);\n  border: 1px dashed var(--border);\n  border-radius: 8px;\n  color: var(--muted);\n}\n\nbutton {\n  background: var(--accent);\n  color: white;\n  border: none;\n  border-radius: 8px;\n  padding: 0.75rem 1.5rem;\n  font-size: 0.95rem;\n  font-weight: 600;\n  cursor: pointer;\n}\n\nbutton:hover:not(:disabled) {\n  background: var(--accent-hover);\n}\n\nbutton:disabled {\n  opacity: 0.6;\n  cursor: not-allowed;\n}\n\n.error {\n  background: rgba(239, 68, 68, 0.1);\n  border: 1px solid var(--error);\n  color: #fca5a5;\n  padding: 0.75rem 1rem;\n  border-radius: 8px;\n  margin-bottom: 1rem;\n  font-size: 0.875rem;\n  white-space: pre-wrap;\n}\n\n.hidden {\n  display: none !important;\n}\n\n.results-grid {\n  display: grid;\n  gap: 1.25rem;\n  margin-top: 2rem;\n}\n\n.dendrogram-img {\n  max-width: 100%;\n  border-radius: 8px;\n  border: 1px solid var(--border);\n  background: white;\n}\n\npre.json-out {\n  margin: 0;\n  padding: 0.75rem;\n  background: var(--bg);\n  border: 1px solid var(--border);\n  border-radius: 8px;\n  overflow: auto;\n  font-size: 0.75rem;\n  max-height: 320px;\n}\n\n.meta-row {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.5rem 1.5rem;\n  font-size: 0.875rem;\n  color: var(--muted);\n  margin-bottom: 1rem;\n}\n\n.meta-row strong {\n  color: var(--text);\n}\n\n.actions {\n  margin-top: 1.25rem;\n}\n'
